const express  = require('express');
const https    = require('https');
const path     = require('path');
const { loadCalendarDays } = require('./calendar-data');

const app = express();

// CORS — permite peticiones desde archivo local y cualquier origen
app.use((req, res, next) => {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET, POST, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');
  if (req.method === 'OPTIONS') { res.sendStatus(200); return; }
  next();
});

app.use(express.json({ limit: '50mb' }));
app.use(express.static(path.join(__dirname, 'public')));

// ── Config ────────────────────────────────────────────
const GH_TOKEN = process.env.GH_TOKEN || '';
const GH_REPO  = 'felipecotelo/auf-prensa';
const GH_FILE  = 'data/state.json';
const GH_API   = 'api.github.com';

// ── GitHub helpers ────────────────────────────────────
function ghRequest(method, path, body) {
  return new Promise((resolve, reject) => {
    const data = body ? JSON.stringify(body) : null;
    const req = https.request({
      hostname: GH_API, path, method,
      headers: {
        'Authorization': 'token ' + GH_TOKEN,
        'User-Agent': 'auf-prensa',
        'Content-Type': 'application/json',
        ...(data ? { 'Content-Length': Buffer.byteLength(data) } : {})
      }
    }, res => {
      let buf = '';
      res.on('data', d => buf += d);
      res.on('end', () => { try { resolve(JSON.parse(buf)); } catch(e) { resolve({}); } });
    });
    req.on('error', reject);
    if (data) req.write(data);
    req.end();
  });
}

async function ghLoad() {
  const d = await ghRequest('GET', `/repos/${GH_REPO}/contents/${GH_FILE}`);
  if (!d.content) return { data: null, sha: null };
  const json = Buffer.from(d.content.replace(/\n/g,''), 'base64').toString('utf8');
  return { data: JSON.parse(json), sha: d.sha };
}

async function ghSave(data, sha) {
  const content = Buffer.from(JSON.stringify(data)).toString('base64');
  return ghRequest('PUT', `/repos/${GH_REPO}/contents/${GH_FILE}`, {
    message: 'sync: ' + new Date().toISOString().slice(0,16).replace('T',' '),
    content, sha
  });
}

// ── Icon embebido ─────────────────────────────────────
const ICON_B64 = '';
app.get('/icon.png', (req, res) => {
  res.setHeader('Content-Type', 'image/png');
  res.setHeader('Cache-Control', 'public, max-age=86400');
  res.send(Buffer.from(ICON_B64, 'base64'));
});

// ── API ───────────────────────────────────────────────
app.get('/api/load', async (req, res) => {
  try {
    const { data, sha } = await ghLoad();
    res.json({ ok: true, data, sha });
  } catch(e) {
    res.json({ ok: false, error: e.message });
  }
});

app.post('/api/save', async (req, res) => {
  try {
    const { sha } = await ghLoad();
    await ghSave(req.body, sha);
    res.json({ ok: true });
  } catch(e) {
    res.json({ ok: false, error: e.message });
  }
});

// ── Calendario .ics (suscribible desde Google Calendar) ───────────────────
// Mismo criterio que el botón "Exportar a Google Calendar" de la app:
// incluye todas las actividades (viajes, entrenamientos, zona mixta, etc.)
// excepto los días de partido (tipo:'partido').
const evKey = (date, idx) => `${date}_${idx}`;
function icsEsc(s) { return String(s || '').replace(/\\/g, '\\\\').replace(/[\n\r]+/g, '\\n').replace(/,/g, '\\,').replace(/;/g, '\\;'); }
function icsDateLocal(date, hh, mm) { return date.replace(/-/g, '') + 'T' + String(hh).padStart(2, '0') + String(mm).padStart(2, '0') + '00'; }
function icsDateOnly(date) { return date.replace(/-/g, ''); }
function icsNextDay(date) { const d = new Date(date + 'T00:00:00Z'); d.setUTCDate(d.getUTCDate() + 1); return d.toISOString().slice(0, 10).replace(/-/g, ''); }
function parseLinks(str) { return (str || '').match(/https?:\/\/\S+/g) || []; }

function buildCalendarICS(lsData) {
  const CALENDAR_DAYS = loadCalendarDays();
  const parse = (key, def) => { try { return JSON.parse(lsData[key] || JSON.stringify(def)); } catch { return def; } };
  const calTimes = parse('auf4_caltimes', {});
  const evTxts   = parse('auf4_evtxt', {});
  const evNotes  = parse('auf4_evnotes', {});
  const evLinks  = parse('auf4_evlink', {});
  const dayActs  = parse('auf4_dayacts', {});

  const lines = ['BEGIN:VCALENDAR', 'VERSION:2.0', 'PRODID:-//AUF FWC26//Calendario prensa//ES', 'CALSCALE:GREGORIAN'];
  const stamp = new Date().toISOString().replace(/[-:]/g, '').split('.')[0] + 'Z';

  CALENDAR_DAYS.forEach(day => {
    if (day.tipo === 'partido') return;
    const customActs = dayActs[day.date] || [];
    const allEvs = [...day.eventos, ...customActs];
    allEvs.forEach((e, realIdx) => {
      if (e.tipo === 'viaje' && !e.txt) return;
      const k = evKey(day.date, realIdx);
      const t = (calTimes[day.date] && calTimes[day.date][realIdx] != null) ? calTimes[day.date][realIdx] : e.h;
      const displayTxt = evTxts[k] || e.txt;
      const note = evNotes[k] || '';
      const link = evLinks[k] || '';
      const descParts = [];
      if (note) descParts.push(note);
      parseLinks(link).forEach(u => descParts.push(u));
      const desc = descParts.join('\\n');
      const m = String(t).match(/(\d{1,2}):(\d{2})/);
      lines.push('BEGIN:VEVENT');
      lines.push('UID:auf-fwc26-' + day.date + '-' + realIdx + '@auf');
      lines.push('DTSTAMP:' + stamp);
      if (m) {
        const hh = parseInt(m[1]), mm = parseInt(m[2]);
        const durMin = e.esTrain ? 15 : 30;
        let endH = hh, endM = mm + durMin;
        if (endM >= 60) { endH += Math.floor(endM / 60); endM %= 60; }
        lines.push('DTSTART:' + icsDateLocal(day.date, hh, mm));
        lines.push('DTEND:' + icsDateLocal(day.date, Math.min(endH, 23), endM));
      } else {
        lines.push('DTSTART;VALUE=DATE:' + icsDateOnly(day.date));
        lines.push('DTEND;VALUE=DATE:' + icsNextDay(day.date));
      }
      lines.push('SUMMARY:' + icsEsc(displayTxt));
      if (desc) lines.push('DESCRIPTION:' + icsEsc(desc));
      if (day.lugar) lines.push('LOCATION:' + icsEsc(day.lugar));
      lines.push('END:VEVENT');
    });
  });
  lines.push('END:VCALENDAR');
  return lines.join('\r\n');
}

// ── Proxy FotMob + ESPN summary (evita CORS desde el browser) ───────
function proxyGet(hostname, path, headers) {
  return new Promise((resolve, reject) => {
    const req = https.request({ hostname, path, method: 'GET', headers: { 'User-Agent': 'Mozilla/5.0 (compatible; AUF-Prensa/1.0)', ...headers } }, res => {
      let buf = '';
      res.on('data', d => buf += d);
      res.on('end', () => { try { resolve(JSON.parse(buf)); } catch(e) { reject(new Error('bad json')); } });
    });
    req.on('error', reject);
    req.end();
  });
}

app.get('/api/fotmob/:matchId', async (req, res) => {
  try {
    const data = await proxyGet('www.fotmob.com', `/api/matchDetails?matchId=${req.params.matchId}`, { Accept: 'application/json', Referer: 'https://www.fotmob.com/' });
    res.json(data);
  } catch(e) {
    res.status(502).json({ error: e.message });
  }
});

app.get('/api/espn/summary/:eventId', async (req, res) => {
  try {
    const data = await proxyGet('site.api.espn.com', `/apis/site/v2/sports/soccer/fifa.world/summary?event=${req.params.eventId}`, {});
    res.json(data);
  } catch(e) {
    res.status(502).json({ error: e.message });
  }
});

app.get('/api/espn/wc/:date', async (req, res) => {
  try {
    const data = await proxyGet('site.api.espn.com', `/apis/site/v2/sports/soccer/fifa.world/scoreboard?dates=${req.params.date}`, {});
    res.json(data);
  } catch(e) {
    res.status(502).json({ error: e.message });
  }
});

app.get('/api/calendar.ics', async (req, res) => {
  try {
    const { data } = await ghLoad();
    const ics = buildCalendarICS((data && data.localStorage) || {});
    res.setHeader('Content-Type', 'text/calendar; charset=utf-8');
    res.setHeader('Content-Disposition', 'inline; filename="auf_fwc26_seleccion.ics"');
    res.send(ics);
  } catch (e) {
    res.status(500).send('Error generando .ics: ' + e.message);
  }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => console.log(`AUF Prensa corriendo en puerto ${PORT}`));
